select t0.project_name, t0.id as projectId, t1.id as collectionId, t1.collection_summary, t1.collection_sign, t1.collection_amount, t1.collection_date, t1.is_collection_historical, t1.collection_ascription, t1.lawyer_id, t1.collection_type, t3.name as lawyerName, t2.document_number, t2.belong_city, t2.belong_province, t2.belong_district from recovery_payment_collection t1 inner join project_info t0 on t0.id = t1.project_id and t0.is_deleted = 0 left join law_firm_info t3 on t3.id = t1.lawyer_id left join subject_info t2 on t2.id = t0.debtor_id and t2.is_deleted = 0 where t1.is_deleted = 0 and t1.collection_status = #{request.status}
AND t1.collection_date BETWEEN
#{item}
AND t0.project_name LIKE CONCAT ('%',#{request.projectName},'%')
AND (t0.affiliated_org IN #{item} OR
t0.manage LIKE CONCAT('%',#{item},'%')
)
AND t0.law_firm_id = #{request.lawyerName}
AND t1.collection_sign = #{request.collectionSign}
AND t1.collection_ascription = #{request.collectionAscription}
ORDER BY t0.id DESC

