left JOIN project_info_ext t1 ON t0.id = t1.id
left join law_firm_info t2 on t0.law_firm_id =t2.id and t2.is_deleted = 0
left join  contract_info t3 on t0.contract_id = t3.id and t3.is_deleted = 0
left join subject_info t4 on t0.debtor_id = t4.id and t4.is_deleted = 0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.compensation_date BETWEEN

      #{item}



    AND t4.belong_province = #{request.province}


    AND t4.belong_city = #{request.city}


    AND t4.belong_district = #{request.district}


    AND t0.manage LIKE CONCAT ('%',#{request.manage},'%')


    AND t0.project_state = #{request.projectState}


    AND t1.industry_type = #{request.industryType}


    AND t0.project_name LIKE CONCAT ('%',#{request.projectName},'%')


    AND t0.law_firm_id =  #{request.lawFirmName}


    AND t0.is_write_off = #{request.isWriteOff}


    AND (t0.affiliated_org IN
          #{item}
      OR

      t0.manage LIKE CONCAT('%',#{item},'%')

    )


